# pip install llama-index-readers-database sqlalchemy psycopg2-binary
from llama_index.readers.database import DatabaseReader

reader = DatabaseReader(
    uri="postgresql://user:pass@localhost:5432/mydb",
)
# Each row becomes a Document; columns become metadata
docs = reader.load_data(
    query="SELECT id, title, body, created_at FROM knowledge_articles WHERE active = true"
)
for doc in docs[:3]:
    print(doc.metadata)   # {'id': 1, 'title': '...', 'created_at': '...'}
    print(doc.text[:100]) # the 'body' column
